const HUE_LABEL={black:'Black',grey:'Grey / Smoke',brown:'Brown',amber:'Amber / Tortoise',yellow:'Yellow',orange:'Orange',rose:'Rose / Red',violet:'Violet',blue:'Blue',teal:'Teal',green:'Green / G-15 / Olive / Khaki',unknown:'Unknown'};
const HUE_COLOR={black:'#1f1f1f',grey:'#656766',brown:'#6b4a34',amber:'#b07a35',yellow:'#d7aa22',orange:'#c9702f',rose:'#9b5265',violet:'#7560a8',blue:'#276d98',teal:'#26777a',green:'#48694c',unknown:'#8a8176'};
const CAT_LABEL={sun:'Sun',tint:'Tint',gradient:'Gradient'};
const FRAME_COLOR={'Tortoise / Brown':'#7a5230','Black / Ink':'#1f1f1f','Clear / Crystal':'#d8d4cc','Grey / Silver':'#9a9a9a','Rose / Red / Purple':'#9b5265','Blue / Navy':'#2d5a8a','Gold / Warm Crystal':'#b89040','Green / Olive':'#4a6644','Other / Mixed':'#8a8176'};
const CAT_STANDARD='<section class="panel" style="margin:14px 0"><h2>镜片类别分类标准 <span class="mut">国际 Cat. 1–3 透光率标准</span></h2><table class="table"><thead><tr><th>类别</th><th>透光率</th><th>适用场景</th><th>本站标注</th></tr></thead><tbody><tr><td><b>Cat. 1</b></td><td>44%–80%</td><td>阴天、室内、时尚装饰，浅色染色镜片</td><td><span class="badge" style="background:#bd6f92">Tint</span></td></tr><tr><td><b>Cat. 2</b></td><td>19%–43%</td><td>多云天气、日常通勤，中度染色太阳镜</td><td><span class="badge" style="background:#bd6f92">Tint</span></td></tr><tr><td><b>Cat. 3</b></td><td>8%–18%</td><td>强光晴天、夏季、海滩，标准深色墨镜</td><td><span class="badge" style="background:#2f2f2f">Sun</span></td></tr><tr><td><b>Gradient</b></td><td>渐变（上深下浅）</td><td>上层 Cat.3 级深度，开车/日常两用</td><td><span class="badge" style="background:#44799a">Gradient</span></td></tr></tbody></table></section>';
const state={catalog:null,insights:null,hue:'brown',query:'',brand:'',cat:'',lensHue:'',frameFamily:'',overrides:{}};
const $=s=>document.querySelector(s);
const el=(tag,cls,html)=>{const n=document.createElement(tag);if(cls)n.className=cls;if(html!=null)n.innerHTML=html;return n};
const safe=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
function loadOverrides(catalogTs){try{const saved=JSON.parse(localStorage.getItem('lensColorOverrides')||'{}');const savedTs=localStorage.getItem('lensColorOverrides_catalogTs');if(savedTs&&savedTs!==catalogTs){console.warn('Catalog updated, clearing stale local overrides');localStorage.removeItem('lensColorOverrides');localStorage.removeItem('lensColorOverrides_catalogTs');return{}}localStorage.setItem('lensColorOverrides_catalogTs',catalogTs);return saved}catch(err){console.warn('Could not read manual overrides',err);return{}}}
function persistOverrides(){try{localStorage.setItem('lensColorOverrides',JSON.stringify(state.overrides||{},null,2));return true}catch(err){console.warn('Could not save manual overrides',err);return false}}
function overrideCount(){return Object.keys(state.overrides||{}).length}
function normalizeHue(hue){return hue==='olive'?'green':hue}
function applyOverrides(){const map=state.overrides||{};(state.catalog?.records||[]).forEach(r=>{if(r.lensHue==='olive')r.lensHue='green';const o=map[r.id];if(o){if(o.lensHue)r.lensHue=normalizeHue(o.lensHue);if(o.cat)r.cat=o.cat;r.hueSource='reviewed-correction'}})}
function showSaved(msg){let n=$('#saveStatus');if(!n){n=document.createElement('div');n.id='saveStatus';n.className='saveStatus';document.body.appendChild(n)}n.textContent=msg;n.classList.add('show');clearTimeout(showSaved.timer);showSaved.timer=setTimeout(()=>n.classList.remove('show'),1600)}
function saveManualOverride(id,hue,cat){const r=state.catalog.records.find(x=>x.id===id);if(!r){alert('Could not find this product in the catalog.');return}state.overrides={...(state.overrides||{}),[id]:{id,brand:r.brand,product:r.product,lensName:r.lensName,frameColor:r.frameColor,lensHue:normalizeHue(hue),cat,hueHex:r.hueHex||'',hueSource:'reviewed-correction',updatedAt:new Date().toISOString()}};persistOverrides();applyOverrides();renderCatalog();renderTop();showSaved('Saved in this page. Export once when done.')}
function downloadText(name,text){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([text],{type:'application/json'}));a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),500)}
function exportOverrides(){const count=overrideCount();if(!count){alert('No manual overrides saved yet. Change a card dropdown first, or click Save on a card.');return}downloadText('lens-color-overrides.json',JSON.stringify(state.overrides||{},null,2))}
function clearOverrides(){if(confirm('Clear local manual overrides in this browser?')){state.overrides={};localStorage.removeItem('lensColorOverrides');location.reload()}}
async function init(){const [catalog,insights]=await Promise.all([fetch('./data/catalog.json?v=hex-calibrated').then(r=>r.json()),fetch('./data/insights.json?v=hex-calibrated').then(r=>r.json())]);state.catalog=catalog;state.insights=insights;state.overrides=loadOverrides(catalog.generatedAt);applyOverrides();renderTop();bindNav();renderAll()}
function bindNav(){document.querySelectorAll('.navBtn').forEach(btn=>btn.addEventListener('click',()=>{document.querySelectorAll('.navBtn').forEach(b=>b.classList.toggle('active',b===btn));document.querySelectorAll('.view').forEach(v=>v.classList.toggle('active',v.id===btn.dataset.view));renderView(btn.dataset.view)}))}
function renderAll(){['overview','hue','pairing','market','catalog','data'].forEach(renderView)}
function renderTop(){const t=state.insights.totals;$('#topStats').innerHTML='<div class="stat"><b>'+t.records+'</b><span>colorways</span></div><div class="stat"><b>'+t.classifiers+'</b><span>editable colors</span></div><div class="stat"><b>'+Object.keys(t.brands).length+'</b><span>brands</span></div>'}
function renderView(id){if(id==='overview')renderOverview();if(id==='hue')renderHueLab();if(id==='pairing')renderPairings();if(id==='market')renderMarket();if(id==='catalog')renderCatalog();if(id==='data')renderDataAdmin()}
function metric(label,value){return '<div class="bigMetric"><b>'+value+'</b><span>'+label+'</span></div>'}
function group(rows,key){const m={};rows.forEach(r=>{const k=typeof key==='function'?key(r):r[key];m[k]=(m[k]||0)+1});return m}
function sortedEntries(obj){return Object.entries(obj).sort((a,b)=>b[1]-a[1]||String(a[0]).localeCompare(String(b[0])))}
function sumValues(obj){return Object.values(obj).reduce((a,b)=>a+b,0)}
function openCatalog(filter){state.query=filter.query||'';state.brand=filter.brand||'';state.cat=filter.cat||'';state.lensHue=filter.lensHue||'';state.frameFamily=filter.frameFamily||'';document.querySelector('[data-view="catalog"]').click()}
function openHue(hue){state.hue=hue;document.querySelector('[data-view="hue"]').click()}
function donut(title,counts,colors,onClickAttr){const total=sumValues(counts)||1;let acc=0;const stops=Object.entries(counts).map(([k,v])=>{const start=acc/total*100;acc+=v;const end=acc/total*100;return (colors[k]||'#999')+' '+start.toFixed(2)+'% '+end.toFixed(2)+'%'}).join(',');return '<section class="panel"><h2>'+title+'</h2><div class="donutWrap"><div class="donut" style="background:conic-gradient('+stops+')"></div><div class="legend">'+Object.entries(counts).map(([k,v])=>'<button class="legendBtn" '+onClickAttr(k)+'><span class="legendSw" style="background:'+(colors[k]||'#999')+'"></span><span>'+safe(CAT_LABEL[k]||HUE_LABEL[k]||k)+'</span><b>'+v+'</b></button>').join('')+'</div></div></section>'}
function barChart(title,entries,max,mode){return '<section class="panel"><h2>'+title+'</h2><div class="barList">'+entries.map(([k,v])=>'<button class="clickBar" data-'+mode+'="'+safe(k)+'"><span><b>'+(HUE_LABEL[k]||k)+'</b></span><span class="barTrack"><span class="barFill" style="display:block;width:'+(v/max*100).toFixed(1)+'%;background:'+(HUE_COLOR[k]||'#222')+'"></span></span><b>'+v+'</b></button>').join('')+'</div></section>'}
function stackBarChart(title,rows,segments,colors,kind){const max=Math.max(...rows.map(r=>sumValues(r.counts)),1);return '<section class="panel"><h2>'+title+'</h2><p class="chartNote">每条堆叠条可点击，进入对应品牌或类别样本。</p><div class="barList">'+rows.map(row=>'<div class="barRow"><button class="legendBtn" data-'+kind+'="'+safe(row.key)+'"><b>'+safe(row.label)+'</b></button><div><div class="stackBar" style="max-width:'+((sumValues(row.counts)/max*100).toFixed(1))+'%">'+segments.map(s=>'<button class="stackSeg" title="'+safe((CAT_LABEL[s]||HUE_LABEL[s]||s)+': '+(row.counts[s]||0))+'" data-'+kind+'="'+safe(row.key)+'" data-seg="'+safe(s)+'" style="width:'+((row.counts[s]||0)/(sumValues(row.counts)||1)*100).toFixed(1)+'%;background:'+(colors[s]||'#999')+'"></button>').join('')+'</div><div class="small">'+segments.map(s=>(CAT_LABEL[s]||HUE_LABEL[s]||s)+' '+(row.counts[s]||0)).join(' · ')+'</div></div><b>'+sumValues(row.counts)+'</b></div>').join('')+'</div></section>'}
function normalizedStackBar(title,rows,segments,colors,kind){return '<section class="panel"><h2>'+title+'</h2><p class="chartNote">各品牌条形等宽（100%），显示类别比例。数字为 SKU 数。</p><div class="barList">'+rows.map(row=>{const total=sumValues(row.counts)||1;return '<div class="barRow"><button class="legendBtn" data-'+kind+'="'+safe(row.key)+'"><b>'+safe(row.label)+'</b></button><div><div class="stackBar" style="max-width:100%">'+segments.map(s=>'<button class="stackSeg" title="'+safe((CAT_LABEL[s]||HUE_LABEL[s]||s)+': '+(row.counts[s]||0)+' ('+((row.counts[s]||0)/total*100).toFixed(0)+'%)')+'" data-'+kind+'="'+safe(row.key)+'" data-seg="'+safe(s)+'" style="width:'+((row.counts[s]||0)/total*100).toFixed(1)+'%;background:'+(colors[s]||'#999')+'"></button>').join('')+'</div><div class="small">'+segments.map(s=>safe(CAT_LABEL[s]||HUE_LABEL[s]||s)+' '+((row.counts[s]||0)/total*100).toFixed(0)+'%').join(' · ')+'</div></div><b>'+total+'</b></div>'}).join('')+'</div></section>'}
function brandHueChart(title,brandHueRows,hueOrder,hueColors){return '<section class="panel"><h2>'+title+'</h2><p class="chartNote">各品牌条形等宽，色块从多到少排列；鼠标停留查看占比。</p><div class="barList">'+brandHueRows.map(row=>{const total=sumValues(row.counts)||1;const segs=Object.entries(row.counts).filter(([h,n])=>n>0).sort((a,b)=>b[1]-a[1]).map(([h])=>h);const top3=segs.slice(0,3).map(h=>safe(HUE_LABEL[h]||h)+' '+((row.counts[h]||0)/total*100).toFixed(0)+'%').join(' · ');return '<div class="barRow"><b>'+safe(row.label)+'</b><div><div class="stackBar" style="max-width:100%">'+segs.map(h=>'<button class="stackSeg" title="'+safe(HUE_LABEL[h]||h)+': '+(row.counts[h]||0)+' ('+((row.counts[h]||0)/total*100).toFixed(0)+'%)" data-hue="'+safe(h)+'" style="width:'+((row.counts[h]||0)/total*100).toFixed(1)+'%;background:'+(hueColors[h]||'#999')+'"></button>').join('')+'</div><div class="small" style="white-space:normal;line-height:1.6;margin-top:3px">'+top3+'</div></div><b>'+total+'</b></div>'}).join('')+'</div></section>'}
function heatMatrix(rows,cols,getVal,max){return '<div class="heatWrap"><div class="heat"><div class="heatRow"><div></div>'+cols.map(c=>'<div class="heatHead">'+safe(c)+'</div>').join('')+'</div>'+rows.map(r=>'<div class="heatRow"><div class="heatHead">'+safe(r)+'</div>'+cols.map(c=>{const v=getVal(r,c);const a=v/max;return '<div class="heatCell" style="background:rgba(30,28,25,'+(0.08+a*.62).toFixed(2)+')">'+(v||'')+'</div>'}).join('')+'</div>').join('')+'</div></div>'}
function hexToHsl(hex){const m=String(hex||'').match(/^#?([0-9a-f]{6})$/i);if(!m)return null;const n=parseInt(m[1],16);let r=((n>>16)&255)/255,g=((n>>8)&255)/255,b=(n&255)/255;const max=Math.max(r,g,b),min=Math.min(r,g,b);let h=0,s=0,l=(max+min)/2;if(max!==min){const d=max-min;s=l>.5?d/(2-max-min):d/(max+min);if(max===r)h=(g-b)/d+(g<b?6:0);else if(max===g)h=(b-r)/d+2;else h=(r-g)/d+4;h*=60}return{h,s:s*100,l:l*100}}
function colorMark(entries){return '<div class="colorMarks">'+entries.map(([h,n])=>'<button class="markChip" data-read-hue="'+safe(h)+'"><span class="markDot" style="background:'+(HUE_COLOR[h]||'#999')+'"></span><span>'+safe(HUE_LABEL[h]||h)+'</span><b>'+n+'</b></button>').join('')+'</div>'}
function pairMark(entries){return '<div class="pairMarks">'+entries.map(([k,n])=>{const [h,f]=k.split('|');return '<button class="pairMark" data-pair-hue="'+safe(h)+'" data-pair-frame="'+safe(f)+'"><span class="markDot" style="background:'+(HUE_COLOR[h]||'#999')+'"></span><span>'+safe((HUE_LABEL[h]||h)+' × '+f)+'</span><b>'+n+'</b></button>'}).join('')+'</div>'}
function spectrumChart(rows){const BRAND_C={'Warby Parker':'#c8763a','MOSCOT':'#3d6b4f','Gentle Monster':'#7b3f8c','Meta AI Glasses':'#3a72a8'};const brands=Object.keys(BRAND_C);const parsed=rows.map(r=>({row:r,hsl:hexToHsl(r.hueHex)})).filter(x=>x.hsl);const cards=brands.map(brand=>{const bp=parsed.filter(x=>x.row.brand===brand);const bins=Array.from({length:24},(_,i)=>({start:i*15,count:0}));const neutrals={black:0,grey:0,light:0};const hexC={};for(const item of bp){const{h,s,l}=item.hsl;const hex=item.row.hueHex;hexC[hex]=(hexC[hex]||0)+1;if(l<18)neutrals.black++;else if(s<12)neutrals.grey++;else if(l>82&&s<28)neutrals.light++;else bins[Math.min(23,Math.floor(h/15))].count++}const maxBin=Math.max(...bins.map(b=>b.count),1);const barsHtml=bins.map(b=>{const hDeg=b.start+7.5;const ht=(6+b.count/maxBin*130).toFixed(1);return'<div class="spectrumBin" style="height:'+ht+'px;background:hsl('+hDeg+' 60% 52%)" title="'+b.start+'–'+(b.start+15)+'°: '+b.count+'"><span>'+(b.count||'')+'</span></div>'}).join('');const topHex=Object.entries(hexC).sort((a,b)=>b[1]-a[1]).slice(0,4).map(([hex,n])=>'<div class="hexSwatch"><span class="hexBox" style="background:'+hex+'"></span><span>'+hex+'</span><b>'+n+'</b></div>').join('');const neutralHtml='<div style="display:flex;gap:6px;flex-wrap:wrap;margin-top:6px">'+'<span class="markChip" style="padding:2px 6px;font-size:10px"><span class="markDot" style="background:#171717;width:10px;height:10px"></span>Black '+neutrals.black+'</span>'+'<span class="markChip" style="padding:2px 6px;font-size:10px"><span class="markDot" style="background:#777;width:10px;height:10px"></span>Grey '+neutrals.grey+'</span>'+(neutrals.light?'<span class="markChip" style="padding:2px 6px;font-size:10px"><span class="markDot" style="background:#d8e2e2;width:10px;height:10px"></span>Light '+neutrals.light+'</span>':'')+'</div>';return'<div class="panel" style="min-width:0"><h3 style="display:flex;align-items:center;gap:7px;margin-bottom:8px"><span style="width:12px;height:12px;border-radius:50%;background:'+BRAND_C[brand]+';flex:0 0 auto;border:1px solid rgba(0,0,0,.12)"></span>'+safe(brand)+'</h3><div class="spectrumBars" style="align-items:flex-end;height:150px;padding:8px 6px 6px">'+barsHtml+'</div><div class="spectrumAxis" style="font-size:9px"><span>0° Red</span><span>60° Yel</span><span>120° Grn</span><span>180° Cyn</span><span>240° Blu</span><span>300° Vio</span></div>'+neutralHtml+'<div class="hexSwatches" style="margin-top:8px">'+topHex+'</div></div>'}).join('');return'<section class="panel" style="margin-top:16px"><h2>镜片色 Hex Spectrum 分布 <span class="mut">各品牌独立</span></h2><p class="chartNote"><b>hueHex 均为镜片颜色编码，非镜架颜色。</b> Warby Parker 使用 15 种标准化镜片参考色；Gentle Monster 由产品图片镜片区域取样；MOSCOT 标准款默认 G-15 绿色，CUSTOM MADE TINTS 使用实际镜片色；Meta 使用官方镜片命名对应色。各品牌独立 Y 轴，柱高反映该品牌内相对分布。</p><div style="display:grid;grid-template-columns:1fr 1fr;gap:12px">'+cards+'</div></section>'}
function renderOverview(){const root=$('#overview');const recs=state.catalog.records;const knownRecs=recs.filter(r=>r.lensHue!=='unknown');const hueRows=state.insights.hueSummary.filter(r=>r.hue!=='unknown').sort((a,b)=>b.brandCount-a.brandCount||b.count-a.count);const catCounts=group(recs,'cat');const frameCounts=group(recs,'frameFamily');const topHue=hueRows[0];const gradientRows=knownRecs.filter(r=>r.cat==='gradient');const gradientHue=sortedEntries(group(gradientRows,'lensHue'));const catColors={sun:'#2f2f2f',tint:'#bd6f92',gradient:'#44799a'};const maxHue=Math.max(...hueRows.map(r=>r.count),1);const maxGrad=Math.max(...gradientHue.map(x=>x[1]),1);const brandCounts=group(recs,'brand');const brandCatRows=Object.keys(brandCounts).map(b=>({key:b,label:b,counts:group(recs.filter(r=>r.brand===b),'cat')}));const brandHueRows=Object.keys(brandCounts).map(b=>({key:b,label:b,counts:group(knownRecs.filter(r=>r.brand===b),'lensHue')}));const frameCols=sortedEntries(frameCounts).slice(0,9).map(x=>x[0]);const heatRows=hueRows.slice(0,9).map(x=>x.hue);const pairMap={};knownRecs.forEach(r=>{const k=r.lensHue+'|'+r.frameFamily;pairMap[k]=(pairMap[k]||0)+1});const maxPair=Math.max(...Object.values(pairMap),1);const brandLensRows=Object.keys(brandCounts).map(b=>{const bRecs=recs.filter(r=>r.brand===b);const distinctHues=[...new Set(bRecs.map(r=>r.lensHue).filter(h=>h&&h!=='unknown'))].sort();const distinctLens=[...new Set(bRecs.map(r=>r.lensName))].sort();return '<tr><td><b>'+safe(b)+'</b></td><td style="text-align:center">'+bRecs.length+'</td><td style="text-align:center"><b>'+distinctHues.length+'</b></td><td>'+distinctHues.map(h=>'<span style="display:inline-flex;align-items:center;gap:3px;margin:2px 6px 2px 0;white-space:nowrap"><span style="width:9px;height:9px;border-radius:50%;background:'+(HUE_COLOR[h]||'#999')+';flex:0 0 auto"></span>'+safe(HUE_LABEL[h]||h)+'</span>').join('')+'</td><td style="color:#a09589;font-size:11px;max-width:220px">'+safe(distinctLens.slice(0,8).join('、'))+(distinctLens.length>8?'…':'')+'</td></tr>'}).join('');const catCompact='<section class="panel"><h2>镜片类别标准</h2><table class="table"><thead><tr><th>类别</th><th>透光率</th><th>分类</th></tr></thead><tbody><tr><td><b>Cat. 1–2</b></td><td><b>19–80%</b><br><span class="mut" style="font-size:10px">浅色 / 时尚镜片</span></td><td><span class="badge" style="background:#bd6f92">Tint</span></td></tr><tr><td><b>Cat. 3</b></td><td><b>8–18%</b><br><span class="mut" style="font-size:10px">强遮光 / 户外必备</span></td><td><span class="badge" style="background:#2f2f2f">Sun</span></td></tr><tr><td><b>Gradient</b></td><td><b>顶部 8–18%<br>底部 19–80%</b><br><span class="mut" style="font-size:10px">上深下浅渐变</span></td><td><span class="badge" style="background:#44799a">Gradient</span></td></tr></tbody></table></section>';const secA='<div class="metricGrid">'+metric('Total SKUs',recs.length)+metric('可分类色相',knownRecs.length)+metric('最高频色相',topHue?HUE_LABEL[topHue.hue]+' · '+topHue.count+'条':'—')+metric('Top 镜架家族',sortedEntries(frameCounts)[0][0])+'</div>';const secHeat='<section class="panel" style="margin-top:14px"><h2>镜片色相 × 镜架家族 搭配热力图</h2><p class="chartNote">颜色越深代表该搭配组合越常见。</p>'+heatMatrix(heatRows,frameCols,(h,f)=>pairMap[h+'|'+f]||0,maxPair)+'</section>';const secCatDefs=(()=>{const catDefs=[{cat:'sun',color:'#2f2f2f',label:'Sun'},{cat:'tint',color:'#bd6f92',label:'Tint'},{cat:'gradient',color:'#44799a',label:'Gradient'}];const brandList=Object.keys(brandCounts);const cols=catDefs.map(({cat,color,label})=>{const catRecs=knownRecs.filter(r=>r.cat===cat);const catTotal=catRecs.length||1;const allHues=sortedEntries(group(catRecs,'lensHue'));const hueBarList='<div style="margin-bottom:14px;padding-bottom:12px;border-bottom:2px solid var(--line)"><div style="font-size:11px;font-weight:800;color:var(--mut);text-transform:uppercase;letter-spacing:.06em;margin-bottom:7px">整体色相分布</div><div style="display:grid;gap:5px">'+allHues.map(([h,n])=>{const pct=(n/catTotal*100).toFixed(1);return'<div style="display:grid;grid-template-columns:80px 1fr 46px;gap:6px;align-items:center"><span style="display:inline-flex;align-items:center;gap:5px;font-size:11px"><span style="width:10px;height:10px;border-radius:50%;background:'+(HUE_COLOR[h]||'#999')+';flex:0 0 auto;border:1px solid rgba(0,0,0,.12)"></span>'+safe(HUE_LABEL[h]||h)+'</span><div class="barTrack"><div class="barFill" style="width:'+pct+'%;background:'+(HUE_COLOR[h]||'#999')+'"></div></div><span style="font-size:11px;font-weight:800;text-align:right">'+pct+'%</span></div>'}).join('')+'</div></div>';const rows=brandList.map(brand=>{const bRecs=catRecs.filter(r=>r.brand===brand);if(!bRecs.length)return'';const hues=sortedEntries(group(bRecs,'lensHue'));const dots=hues.map(([h,n])=>'<span style="display:inline-flex;align-items:center;gap:3px;margin:0 8px 5px 0;white-space:nowrap"><span style="width:11px;height:11px;border-radius:50%;background:'+(HUE_COLOR[h]||'#999')+';flex:0 0 auto;border:1px solid rgba(0,0,0,.12)"></span><span style="font-size:11px">'+safe(HUE_LABEL[h]||h)+'</span><b style="font-size:11px">'+n+'</b></span>').join('');return'<div style="margin-bottom:11px;padding-bottom:11px;border-bottom:1px solid var(--line)"><div style="font-size:12px;font-weight:800;margin-bottom:5px">'+safe(brand)+'</div><div style="display:flex;flex-wrap:wrap">'+dots+'</div></div>'}).filter(Boolean).join('');return'<div class="panel"><h2 style="display:flex;align-items:center;gap:8px"><span class="badge" style="background:'+color+'">'+label+'</span><span style="font-size:13px;font-weight:normal;color:var(--mut)">'+catTotal+' SKU</span></h2>'+hueBarList+rows+'</div>'}).join('');return'<section style="margin-top:14px"><h2 style="margin:0 0 10px;font-size:18px">各类别色相选择 <span class="mut" style="font-size:13px;font-weight:normal">Sun / Tint / Gradient 中各品牌选了哪些颜色</span></h2><div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px">'+cols+'</div></section>'})();const secGuide='<section style="margin-top:14px"><h2 style="margin:0 0 12px;font-size:20px">选色指南 <span style="font-size:13px;font-weight:normal;color:var(--mut)">基于四品牌 2706 条 SKU 数据的第一性原理推导</span></h2><div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px"><div class="panel" style="border-top:3px solid #2f2f2f"><h3 style="margin-bottom:4px">Sun · Cat. 3</h3><p class="chartNote" style="margin-bottom:10px">8–18% 透光率 · 1233 SKU</p><p style="font-size:12px;margin:0 0 10px"><b>核心逻辑：功能决定颜色。</b>强遮光镜片的首要任务是不失真——灰色不偏色、棕色增强自然对比度，这两点决定了市场分布。</p><div style="display:grid;gap:7px;font-size:12px"><div style="background:#f5f0ea;border-radius:7px;padding:9px 11px"><b>🥇 Grey / Smoke — 25.8%</b><br><span class="mut">四家品牌全覆盖。中性色，不改变色相，户外视觉最真实。最安全的主流选择。</span></div><div style="background:#f5f0ea;border-radius:7px;padding:9px 11px"><b>🥈 Brown / Amber — 23.7%</b><br><span class="mut">四家品牌全覆盖。暖色调，增强对比度，晴天户外及驾驶场景首选。</span></div><div style="background:#f5f0ea;border-radius:7px;padding:9px 11px"><b>🥉 Green / G-15 — 22.2%</b><br><span class="mut">三家品牌。历史积淀选择（Ray-Ban / MOSCOT G-15 工艺），色感稳定，专业背书强。</span></div><div style="border:1px solid var(--line);border-radius:7px;padding:9px 11px"><b>差异化区间：Blue · Rose — 各约 11%</b><br><span class="mut">四家品牌均有，但总占比低。选这两色有辨识度，且有品牌共识背书，不属于小众冒险。</span></div></div><p style="font-size:11px;color:#8a7f74;margin:10px 0 0"><b>结论：</b>落在主流区间选 Grey 或 Brown。想在主流中有辨识度选 Blue 或 Rose。</p></div><div class="panel" style="border-top:3px solid #bd6f92"><h3 style="margin-bottom:4px">Tint · Cat. 1–2</h3><p class="chartNote" style="margin-bottom:10px">19–80% 透光率 · 790 SKU</p><p style="font-size:12px;margin:0 0 10px"><b>核心逻辑：Tint 是另一套颜色语言。</b>高透光率意味着颜色不影响遮光功能，品牌有更大空间做颜色表达——导致 Tint 与 Sun 的颜色分布几乎相反。</p><div style="display:grid;gap:7px;font-size:12px"><div style="background:#f5f0ea;border-radius:7px;padding:9px 11px"><b>🥇 Blue — 25.6%</b><br><span class="mut">Sun 中占 11.8%，到 Tint 跃升为第一。蓝色透过高透光率镜片视觉清爽，是 Tint 的核心色。</span></div><div style="background:#f5f0ea;border-radius:7px;padding:9px 11px"><b>🥈 Rose / Pink — 20.8%</b><br><span class="mut">Tint 专属感最强的颜色。在 Sun 只是边缘色（11.7%），在 Tint 升至第二，是时尚镜片的标志性配色。</span></div><div style="background:#f5f0ea;border-radius:7px;padding:9px 11px"><b>🥉 Yellow — 18.7%</b><br><span class="mut">Sun 中几乎不存在（0.2%），Tint 中升至第三。低光/运动场景功能性色，也是鲜明的设计语言。</span></div><div style="border:1px solid var(--line);border-radius:7px;padding:9px 11px"><b>注意：Grey 在 Tint 仅 6.8%</b><br><span class="mut">Sun 的主力灰色在 Tint 里是少数派——说明灰色的存在感来自功能性需求，而非时尚偏好。</span></div></div><p style="font-size:11px;color:#8a7f74;margin:10px 0 0"><b>结论：</b>Tint 选 Blue 是最主流的选择。Rose 是 Tint 场景下最有标志性的颜色。Yellow 适合强化运动/户外定位。</p></div><div class="panel" style="border-top:3px solid #44799a"><h3 style="margin-bottom:4px">Gradient · 渐变</h3><p class="chartNote" style="margin-bottom:10px">顶 8–18% · 底 19–80% · 683 SKU</p><p style="font-size:12px;margin:0 0 10px"><b>核心逻辑：Gradient 无功能性主导色。</b>前五名（Rose 21%、Blue 21%、Grey 20%、Green 18%、Brown 18%）分布极均匀，说明 Gradient 的颜色选择更多由审美和搭配驱动，而非功能需求。</p><div style="display:grid;gap:7px;font-size:12px"><div style="background:#f5f0ea;border-radius:7px;padding:9px 11px"><b>经典稳妥：Grey / Brown Gradient</b><br><span class="mut">中性色渐变，上方遮光、下方透明，视觉干扰最小。驾驶场景的传统解决方案，接受度最广。</span></div><div style="background:#f5f0ea;border-radius:7px;padding:9px 11px"><b>时尚信号：Rose / Blue Gradient</b><br><span class="mut">Gradient 中占比最高的两色（各约 21%）。渐变弱化了鲜艳色的突兀感，是大胆颜色的"安全表达"方式。</span></div><div style="border:1px solid var(--line);border-radius:7px;padding:9px 11px"><b>Gradient 的独特价值</b><br><span class="mut">功能：向下看（手机/仪表盘）透光率高，向前看遮光强。审美：任何颜色做成渐变后视觉接受度都更高——Gradient 是扩展颜色选择的天然缓冲层。</span></div></div><p style="font-size:11px;color:#8a7f74;margin:10px 0 0"><b>结论：</b>没有错误答案。Grey/Brown Gradient 最保守稳妥；Rose/Blue Gradient 是当前市场的时尚主流。</p></div></div><div class="panel" style="margin-top:12px;background:#1d1c1a;color:#e8e0d4"><h3 style="color:#fff;margin-bottom:10px">📊 数据规律总结</h3><div style="display:grid;grid-template-columns:repeat(3,1fr);gap:16px;font-size:12px"><div><b style="color:#c8a87a">颜色的功能-时尚轴</b><p style="color:#a09080;margin:6px 0 0">Grey → Sun 主力（25.8%）→ Tint 少见（6.8%）<br>Blue → Sun 边缘（11.8%）→ Tint 第一（25.6%）<br>Rose → Sun 边缘（11.7%）→ Tint 第二（20.8%）<br><br>规律：颜色越鲜艳，越向 Tint/Gradient 集中；越中性，越向 Sun 集中。</p></div><div><b style="color:#c8a87a">四品牌共识即市场共识</b><p style="color:#a09080;margin:6px 0 0">Sun 中 Grey + Brown 各被四家品牌全覆盖。四家品牌独立调研、独立定价，仍得出同样结论——这是市场验证的结果，不是巧合。<br><br>单品牌主导的颜色（如 MOSCOT 的 Green）需结合品牌定位判断，不能直接视为普适主流。</p></div><div><b style="color:#c8a87a">选色优先级建议</b><p style="color:#a09080;margin:6px 0 0">① 先定类别（Sun / Tint / Gradient）<br>② 在该类别中选 Top 2 色 = 主流区间<br>③ 用 Top 3–4 色 = 有差异度但有品牌背书<br>④ 超出 Top 4 = 小众/实验性，需要更强的设计理由<br><br>Gradient 是例外：五色均分，无明显主流，从审美出发即可。</p></div></div></div></section>';const secGrid2='<div class="grid2" style="margin-top:14px"><section class="panel"><h2>各品牌镜片色相 <span class="mut">各品牌实际 offer 的色相种类</span></h2><p class="chartNote">色相由 lensHue 统计，排除 unknown。产品图片展示镜架+镜片整体，视觉主色由镜架主导。</p><table class="table"><thead><tr><th>品牌</th><th style="text-align:center">SKU</th><th style="text-align:center">色相数</th><th>色相分布</th><th style="color:#a09589">原始镜片命名</th></tr></thead><tbody>'+brandLensRows+'</tbody></table><div style="margin-top:10px;font-size:11px;color:#8a7f74;border-top:1px solid var(--line);padding-top:8px"><b>数据说明：</b>Warby Parker — 官方标准化镜片体系，15 种镜片类型跨所有镜架共用。MOSCOT — 标准 Sun 款原始命名为镜架醋酸颜色（如 Flesh、Crystal、Tortoise），实际镜片默认为 G-15 绿色；CUSTOM MADE TINTS / MONOCHROME 系列例外，有独立镜片色。Gentle Monster — 原始数据仅区分 Sun lens / Tint lens，色相由图片取样 hex 推导。Meta — 官方命名包含镜片类型（如 Transitions、Sapphire、Ruby）。</div></section><div style="display:flex;flex-direction:column;gap:12px">'+catCompact+(()=>{const tot=sumValues(catCounts)||1;return'<section class="panel"><h2>类别构成</h2><div class="barList">'+Object.entries(catCounts).sort((a,b)=>b[1]-a[1]).map(([cat,n])=>{const pct=(n/tot*100).toFixed(1);return'<div class="barRow"><b><span class="badge" style="background:'+catColors[cat]+'">'+safe(CAT_LABEL[cat]||cat)+'</span></b><div class="barTrack"><div class="barFill" style="width:'+pct+'%;background:'+catColors[cat]+'"></div></div><b>'+pct+'%<span class="mut" style="font-size:11px;margin-left:5px">'+n+'</span></b></div>'}).join('')+'</div></section>'})()+'</div></div>';const secChartGrid='<div class="chartGrid" style="margin-top:14px">'+barChart('色相分布排名',hueRows.map(r=>[r.hue,r.count]),maxHue,'hue')+normalizedStackBar('各品牌类别构成',brandCatRows,['sun','tint','gradient'],catColors,'brand')+brandHueChart('各品牌色相偏好',brandHueRows,state.insights.hueOrder.filter(h=>h!=='unknown'),HUE_COLOR)+'</div>';const secSpectrum=spectrumChart(knownRecs);const secConclusion=(()=>{const targetFrames=[{family:'Tortoise / Brown',label:'Brown / Tortoise 镜架',frameHex:'#7a5230'},{family:'Black / Ink',label:'Black / Ink 镜架',frameHex:'#1f1f1f'}];const panels=targetFrames.map(({family,label,frameHex})=>{const fr=knownRecs.filter(r=>r.frameFamily===family);const tot=fr.length;const byHue=sortedEntries(group(fr,'lensHue'));const hueCards=byHue.slice(0,5).map(([hue,cnt])=>{const pct=(cnt/tot*100).toFixed(1);const brandSet=[...new Set(fr.filter(r=>r.lensHue===hue).map(r=>r.brand))];const brandCount=brandSet.length;const hexMap={};fr.filter(r=>r.lensHue===hue&&r.hueHex).forEach(r=>{hexMap[r.hueHex]=(hexMap[r.hueHex]||0)+1});const topHex=Object.entries(hexMap).sort((a,b)=>b[1]-a[1]).slice(0,3);const exByBrand={};fr.filter(r=>r.lensHue===hue&&r.img).forEach(r=>{if(!exByBrand[r.brand])exByBrand[r.brand]=r});const examples=Object.values(exByBrand);const starBadge=brandCount===4?'<span style="background:#d4a017;color:#fff;border-radius:999px;padding:1px 6px;font-size:9px;font-weight:900;margin-left:5px">4/4品牌</span>':brandCount===3?'<span style="background:#7a9a5a;color:#fff;border-radius:999px;padding:1px 6px;font-size:9px;font-weight:900;margin-left:5px">3/4品牌</span>':'<span style="background:#aaa;color:#fff;border-radius:999px;padding:1px 6px;font-size:9px;font-weight:900;margin-left:5px">'+brandCount+'/4品牌</span>';const hexSwatches=topHex.map(([hex,n])=>'<span style="display:inline-flex;align-items:center;gap:3px;margin-right:6px"><span style="width:13px;height:13px;border-radius:3px;background:'+hex+';border:1px solid rgba(0,0,0,.15);flex:0 0 auto"></span><span style="font-family:monospace;font-size:10px">'+hex+'</span><span style="font-size:10px;color:var(--mut)">×'+n+'</span></span>').join('');const miniExamples=examples.slice(0,4).map(r=>'<div style="display:flex;align-items:center;gap:6px;padding:5px 0;border-bottom:1px solid var(--line)"><img src="'+r.img+'" style="width:36px;height:36px;object-fit:contain;border-radius:4px;background:#f3f3f3;flex:0 0 auto"><div style="min-width:0"><div style="font-size:10px;font-weight:800;color:var(--mut)">'+safe(r.brand)+'</div><div style="font-size:11px;font-weight:800;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+safe(r.product)+'</div><div style="font-size:10px;color:var(--mut)">'+safe(r.lensName)+'</div></div></div>').join('');return'<div style="border:1px solid var(--line);border-radius:8px;padding:11px;background:#fff"><div style="display:flex;align-items:center;gap:7px;margin-bottom:7px"><span style="width:13px;height:13px;border-radius:50%;background:'+(HUE_COLOR[hue]||'#999')+';flex:0 0 auto;border:1px solid rgba(0,0,0,.12)"></span><b style="font-size:13px">'+safe(HUE_LABEL[hue]||hue)+'</b>'+starBadge+'<span style="margin-left:auto;font-size:12px;font-weight:800">'+pct+'%</span></div><div style="margin-bottom:7px">'+hexSwatches+'</div><div>'+miniExamples+'</div></div>'}).join('');return'<div class="panel" style="min-width:0"><div style="display:flex;align-items:center;gap:10px;margin-bottom:12px;padding-bottom:10px;border-bottom:2px solid var(--line)"><span style="width:18px;height:18px;border-radius:4px;background:'+frameHex+';flex:0 0 auto;border:1px solid rgba(0,0,0,.18)"></span><b style="font-size:16px">'+label+'</b><span class="mut" style="font-size:12px">'+tot+' SKU</span></div><div style="display:grid;gap:9px">'+hueCards+'</div></div>'}).join('');return'<section style="margin-top:14px"><h2 style="margin:0 0 10px;font-size:20px">配色结论 <span style="font-size:13px;font-weight:normal;color:var(--mut)">基于数据库实际搭配频次 — Brown/Tortoise & Black 镜架</span></h2><p class="chartNote" style="margin-bottom:10px">命中率 = 该镜架 × 该镜片色相在四家品牌中的出现频次占比；品牌数 = 有多少家品牌做了这个搭配。</p><div style="display:grid;grid-template-columns:1fr 1fr;gap:12px">'+panels+'</div></section>'})();const secHueNav='<section class="panel" style="margin-top:14px"><h2>色相导航 <span class="mut">点击进入 Hue Lab</span></h2><div class="swatchBoard">'+hueRows.map(r=>'<button class="swatch" style="background:'+HUE_COLOR[r.hue]+'" data-hue="'+r.hue+'">'+HUE_LABEL[r.hue]+'<br><span style="font-size:10px;opacity:.8">'+r.count+'</span></button>').join('')+'</div></section>';root.innerHTML=secA+secHeat+secCatDefs+secGuide+secGrid2+secChartGrid+secSpectrum+secConclusion+secHueNav;root.querySelectorAll('[data-hue]').forEach(b=>b.onclick=()=>openHue(b.dataset.hue));root.querySelectorAll('[data-cat]').forEach(b=>b.onclick=()=>openCatalog({cat:b.dataset.cat}));root.querySelectorAll('[data-brand]').forEach(b=>b.onclick=()=>openCatalog({brand:b.dataset.brand}));root.querySelectorAll('.stackSeg[data-hue]').forEach(b=>b.onclick=(e)=>{e.stopPropagation();openHue(b.dataset.hue)})}
function hueButtons(){return '<div class="hueButtons">'+state.insights.hueOrder.map(h=>'<button class="hueBtn '+(state.hue===h?'active':'')+'" data-hue="'+h+'">'+HUE_LABEL[h]+'</button>').join('')+'</div>'}
function productCard(r){const lensColor=r.hueHex||(HUE_COLOR[r.lensHue]||'#ccc');const frameColor=FRAME_COLOR[r.frameFamily]||'#8a8176';const hueOptions=Object.keys(HUE_LABEL).map(h=>'<option value="'+h+'" '+(r.lensHue===h?'selected':'')+'>'+HUE_LABEL[h]+'</option>').join('');const catOptions=Object.keys(CAT_LABEL).map(c=>'<option value="'+c+'" '+(r.cat===c?'selected':'')+'>'+CAT_LABEL[c]+'</option>').join('');const colorBar='<div style="display:flex;gap:0;height:34px;border-radius:6px;overflow:hidden;margin-bottom:8px;border:1px solid rgba(0,0,0,.1)"><div style="flex:1;background:'+frameColor+';display:flex;align-items:center;justify-content:center;gap:4px;font-size:10px;font-weight:800;color:#fff;text-shadow:0 1px 2px rgba(0,0,0,.6);letter-spacing:.03em">镜架</div><div style="flex:1;background:'+lensColor+';display:flex;align-items:center;justify-content:center;gap:4px;font-size:10px;font-weight:800;color:#fff;text-shadow:0 1px 2px rgba(0,0,0,.6);letter-spacing:.03em">镜片</div></div>';return '<figure class="productCard" data-id="'+safe(r.id)+'"><img loading="lazy" src="'+r.img+'" alt="'+safe(r.product)+'"><figcaption>'+colorBar+'<b>'+safe(r.brand)+'</b><br>'+safe(r.product)+'<br><span class="small" style="color:#8a7a6a">镜架 '+safe(r.frameColor)+'</span><br><span class="small">镜片 '+safe(HUE_LABEL[r.lensHue]||r.lensHue)+' · '+safe(r.lensName)+'</span><br><span class="badge">'+CAT_LABEL[r.cat]+'</span><div class="calib"><span class="calibSw" style="background:'+lensColor+'"></span><span>'+safe(r.hueHex||'—')+'</span></div><div class="manualFix"><select class="miniSelect manualHue">'+hueOptions+'</select><select class="miniSelect manualCat">'+catOptions+'</select><button class="miniBtn saveFix" type="button">Save</button></div></figcaption></figure>'}
function bindManualSave(root){root.querySelectorAll('.saveFix').forEach(btn=>btn.addEventListener('click',()=>{const card=btn.closest('.productCard');saveManualOverride(card.dataset.id,card.querySelector('.manualHue').value,card.querySelector('.manualCat').value)}))}
function renderHueLab(){const root=$('#hue');const d=state.insights.byHue[state.hue];const hueColor=HUE_COLOR[state.hue]||'#999';const totalRecs=Object.values(d.brandCounts).reduce((a,b)=>a+b,0);const brandRows=Object.entries(d.brandCounts).sort((a,b)=>b[1]-a[1]).map(([b,n])=>'<div class="barRow"><b>'+safe(b)+'</b><div class="barTrack"><div class="barFill" style="width:'+(n/totalRecs*100).toFixed(1)+'%;background:'+hueColor+'"></div></div><b>'+n+'</b></div>').join('');const catRows=Object.entries(d.categoryCounts).sort((a,b)=>b[1]-a[1]).map(([c,n])=>'<div class="barRow"><b>'+safe(CAT_LABEL[c]||c)+'</b><div class="barTrack"><div class="barFill" style="width:'+(n/totalRecs*100).toFixed(1)+'%;background:'+hueColor+'"></div></div><b>'+n+'</b></div>').join('');const SRC_PRIORITY={'gm-lens-image-hex':0,'source-hex':1,'reviewed-correction':2,'name-to-reference-hex':3,'name-keyword':4};const imageExamples=state.catalog.records.filter(r=>r.lensHue===state.hue&&r.img&&r.brand!=='Warby Parker').sort((a,b)=>(SRC_PRIORITY[a.hueSource]??5)-(SRC_PRIORITY[b.hueSource]??5)||a.rank-b.rank).filter((r,i,arr)=>arr.findIndex(x=>x.brand===r.brand&&x.product===r.product&&x.lensName===r.lensName)===i).slice(0,12);const imgNote=imageExamples.length?'<p class="chartNote">图片来源：GM 由产品图镜片区域取样 · MOSCOT/Meta 使用官方镜片色。Warby Parker 因产品图以镜架为主、镜片色不易辨认，不在此展示。</p>':'<p class="chartNote">此色相暂无适合展示的非 Warby Parker 图片样本。</p>';root.innerHTML=hueButtons()+'<div style="display:flex;align-items:center;gap:16px;background:'+hueColor+'18;border:1px solid '+hueColor+'55;border-radius:8px;padding:14px 18px;margin-bottom:14px"><div style="width:52px;height:52px;border-radius:10px;background:'+hueColor+';flex:0 0 auto;border:1px solid rgba(0,0,0,.15)"></div><div><b style="font-size:16px">'+safe(HUE_LABEL[state.hue])+'</b><p style="margin:3px 0 0;font-size:12px;color:#6a6058">'+totalRecs+' 条记录 · '+d.variants.length+' 种镜片命名 · '+Object.keys(d.brandCounts).length+' 个品牌</p></div></div><div class="detailLayout"><aside class="panel"><h2>镜片命名列表</h2><div class="variantList">'+d.variants.slice(0,80).map(v=>'<div class="variant"><div><b>'+safe(v.name)+'</b><span class="small">'+v.brands.join(' / ')+'</span></div><b>'+v.count+'</b></div>').join('')+'</div></aside><div style="display:flex;flex-direction:column;gap:12px"><section class="panel"><h2>品牌分布</h2><div class="barList">'+brandRows+'</div></section><section class="panel"><h2>类别构成</h2><div class="barList">'+catRows+'</div></section></div></div>'+(imageExamples.length?'<section class="panel" style="margin-top:14px"><h2>镜片色案例图</h2>'+imgNote+'<div class="imageGrid">'+imageExamples.map(productCard).join('')+'</div></section>':'<section class="panel" style="margin-top:14px"><h2>镜片色案例图</h2>'+imgNote+'</section>');root.querySelectorAll('.hueBtn').forEach(b=>b.onclick=()=>{state.hue=b.dataset.hue;renderHueLab()});bindManualSave(root)}
function pairCases(hue,frame){return state.catalog.records.filter(r=>r.lensHue===hue&&r.frameFamily===frame).sort((a,b)=>a.rank-b.rank).filter((r,i,a)=>a.findIndex(x=>x.brand===r.brand&&x.product===r.product&&x.lensName===r.lensName)===i).slice(0,3)}
function miniCase(r){return '<div class="caseMini"><img loading="lazy" src="'+r.img+'" alt="'+safe(r.product)+'"><div><b>'+safe(r.brand)+'</b><br>'+safe(r.product)+'<br><span class="small">镜片 '+safe(r.lensName)+' / '+safe(r.frameColor)+'</span></div></div>'}
function renderPairings(){const root=$('#pairing');const rows=state.insights.hueOrder.filter(h=>h!=='unknown').map(h=>({h,frames:state.insights.frameByHue[h]||[]})).filter(x=>x.frames.length);root.innerHTML='<section class="panel"><h2>Lens hue × frame family cases</h2><p class="chartNote">每张卡先列高频镜框家族，再给真实产品图。Unknown 记录保留在 Catalog 中人工校准，不进入搭配趋势。</p><div class="pairCards">'+rows.map(x=>'<div class="pairCard"><b style="color:'+HUE_COLOR[x.h]+'">'+HUE_LABEL[x.h]+'</b><p class="mut">'+x.frames.slice(0,3).map(f=>f.frameFamily+' ('+f.count+')').join(' · ')+'</p>'+x.frames.slice(0,3).map(f=>'<div style="margin-top:10px"><b>'+f.frameFamily+'</b><span class="small"> · '+f.count+' records · examples: '+f.examples.slice(0,3).join(', ')+'</span><div class="caseGrid">'+pairCases(x.h,f.frameFamily).map(miniCase).join('')+'</div></div>').join('')+'</div>').join('')+'</div></section>';root.querySelectorAll('.caseMini').forEach(card=>card.onclick=()=>{openCatalog({query:card.textContent.trim().split('\n').slice(-1)[0]||''})})}
function brandTopCases(brand){const rows=state.catalog.records.filter(r=>r.brand===brand&&r.img).sort((a,b)=>a.rank-b.rank||String(a.product).localeCompare(String(b.product)));const out=[];const seen=new Set();for(const r of rows){const key=brand==='Warby Parker'?r.product:(brand==='Gentle Monster'?r.product:r.product+'|'+r.frameColor+'|'+r.lensName);if(seen.has(key))continue;seen.add(key);out.push(r);if(out.length===3)break}return out}
function signalCases(brand,terms){const rows=state.catalog.records.filter(r=>r.brand===brand&&r.img).sort((a,b)=>a.rank-b.rank||String(a.product).localeCompare(String(b.product)));const out=[];const seen=new Set();for(const term of terms){const q=term.toLowerCase();const hit=rows.find(r=>!seen.has(r.product+'|'+r.frameColor+'|'+r.lensName)&&(r.product+' '+r.frameColor+' '+r.lensName+' '+r.lensHue+' '+r.cat).toLowerCase().includes(q));if(hit){seen.add(hit.product+'|'+hit.frameColor+'|'+hit.lensName);out.push(hit)}}for(const r of rows){if(out.length>=3)break;const key=r.product+'|'+r.frameColor+'|'+r.lensName;if(seen.has(key))continue;seen.add(key);out.push(r)}return out.slice(0,3)}
function bulletList(items){return '<ul>'+items.map(x=>'<li>'+x+'</li>').join('')+'</ul>'}
function caseStrip(rows){return '<div class="topCaseGrid">'+rows.map(miniCase).join('')+'</div>'}
function sourcePills(items){return '<div class="brandSources">'+items.map(s=>'<a class="sourcePill" href="'+s.url+'" target="_blank" rel="noreferrer">'+s.label+'</a>').join('')+'</div>'}
function renderMarket(){const root=$('#market');const recs=state.catalog.records;const market=[{brand:'Gentle Monster',status:'官网实时待确认',newness:['当前页面先不硬写“newest”：官网实时 merchandising 还没有接稳定 scraper。','本地 best-selling 抓取显示前排以 Black 为核心，随后出现 Brown / Tortoise / Silver。','建议下一步抓取官网 sunglasses 列表的 New / Campaign / Hero 模块，单独落到 market_signals.json。'],hero:['本地首屏排序的强信号是 Black lens + Black frame。','Brown / Tortoise 是第二层商业安全色，可作为黑色之后的补充墙。','Silver / Grey 更适合金属或轻量造型，不应替代黑棕基本盘。'],newTerms:['Black','Brown','Tortoise'],heroTerms:['Black','Brown','Silver'],note:'Top3 来自本地 best-selling 排序。新上与主图推色暂不伪造，等待官网 scraper。',sources:[{label:'Local best-selling scrape',url:'./data/catalog.json'}]},{brand:'Meta AI Glasses',status:'官网确认 + 本地样本',newness:['官网当前新/featured 家族可见 Starfire Kylie Edition、Adventurer、Fury。','新色语言集中在 Classic Black、Dark Tortoise + Chocolate、Transitions Grey，以及 Merlot/Ruby、Linen/Sapphire 这类 tech color naming。','对我们有用的不是单纯 hue，而是“经典框色 + 功能镜片名”的组合。'],hero:['当前主推更偏 AI glasses family：黑、玳瑁/巧克力、灰变色是最稳的三组。','Fury / Adventurer 扩展出 Green、Dark Amber、Light Blue Atlantic、Sapphire、Ruby，适合做运动/科技感色彩带。','Meta 的颜色墙应把 Transitions 单独标注，不能只归成普通 Grey。'],newTerms:['Starfire Kylie Edition Classic Black','Dark Tortoise','Transitions Grey'],heroTerms:['Brown','Green','Sapphire'],note:'Top3 使用本地抓取中的 featured 排序；官网信号来自 Meta AI glasses shop-all。',sources:[{label:'Meta official shop-all',url:'https://www.meta.com/ai-glasses/shop-all/'},{label:'Local featured scrape',url:'./data/catalog.json'}]},{brand:'Warby Parker',status:'官网确认 + 本地样本',newness:['官网 sunglasses shelf 有 New arrivals，并把 Boaz 作为夏季 newest bestseller 露出。','官网定制 tint 色彩包括 Blue、Yellow、Rosy Brown；另有新 tortoise shell + green lenses 的促销语言。','Warby 的商业逻辑是“热门框型 + 多镜片系统”，颜色分析要按 frame 和 lens 分开看。'],hero:['当前主推可读作 Tortoise/Black Walnut 框色 + Blue/Green/Brown/Grey 镜片系统。','Blue 在本地 top frames 的默认抓取里非常突出，但它更像 lens option 的首位展示，不一定等于所有销量第一。','适合把 Blue tint/blue sun 做成入口色，再用 Green/Brown/Grey 承接常规转化。'],newTerms:['Blue','Yellow','Rose'],heroTerms:['Tortoise','Green','Black Walnut'],note:'Top3 按本地 best-selling top frames 去重；镜片显示抓取里的第一组默认 lens。',sources:[{label:'Warby official sunglasses',url:'https://www.warbyparker.com/sunglasses'},{label:'Local best-selling scrape',url:'./data/catalog.json'}]},{brand:'MOSCOT',status:'官网实时待确认',newness:['当前页面先不硬写官方 newest：MOSCOT 官网实时列表还没有接稳定 scraper。','本地数据里 CUSTOM MADE TINTS、NYC Champs、Rose+ 等可作为 seasonal/tint 风格组继续追踪。','LEMTOSH SUN 在 best-selling 样本中权重极高，应先分析它的颜色展开，而不是平均看全站。'],hero:['本地前排是 LEMTOSH SUN：Flesh、Black、Blonde、Tortoise G-15、Cosmitan Brown。','经典商业组合是 Black / Tortoise / Brown / G-15；Flesh、Blonde 更像品牌调性的 tint/acetate 特色。','MOSCOT 适合单独做“经典款多色展开”视图，避免被其他品牌的 SKU 结构稀释。'],newTerms:['Flesh','Blonde','Ruby'],heroTerms:['Tortoise with G-15','Black','Cosmitan Brown'],note:'Top3 来自本地 best-selling 排序，同一 bestseller 产品下展示前三个颜色搭配。',sources:[{label:'Local best-selling scrape',url:'./data/catalog.json'}]}];const cats=group(recs,'cat');const cards=market.map(m=>'<article class="brandSignalCard"><div class="brandSignalHead"><div><h3>'+safe(m.brand)+'</h3><p class="mut">'+safe(m.note)+'</p></div><span class="evidencePill">'+safe(m.status)+'</span></div><div class="signalCols"><div class="signalCol"><h4>1. 新上的颜色</h4>'+bulletList(m.newness)+caseStrip(signalCases(m.brand,m.newTerms))+'</div><div class="signalCol"><h4>2. 主图/官网当前推色</h4>'+bulletList(m.hero)+caseStrip(signalCases(m.brand,m.heroTerms))+'</div><div class="signalCol"><h4>3. Bestselling Top3 搭配</h4>'+caseStrip(brandTopCases(m.brand))+sourcePills(m.sources)+'</div></div></article>').join('');root.innerHTML='<div class="metricGrid">'+metric('Brand signal cards',market.length)+metric('Sun / Tint / Gradient',cats.sun+' / '+cats.tint+' / '+cats.gradient)+metric('Official current checks','Meta / Warby')+metric('Local top3 basis','Best-selling scrape')+'</div><section class="panel" style="margin-top:16px"><h2>Market Signals by Brand</h2><p class="chartNote">每家拆成三个维度：新上颜色、当前主图/官网推色、best-selling top3 搭配。每个维度都配本地 catalog 的实际产品图；没有稳定官网实时证据的品牌会明确标“待确认”。</p><div class="brandSignalGrid">'+cards+'</div></section><section class="panel" style="margin-top:16px"><h2>Evidence notes</h2><table class="table"><thead><tr><th>Brand</th><th>Current-source confidence</th><th>How to read the top3</th></tr></thead><tbody>'+market.map(m=>'<tr><td>'+safe(m.brand)+'</td><td>'+safe(m.status)+'</td><td>'+safe(m.note)+'</td></tr>').join('')+'</tbody></table></section>';root.querySelectorAll('.caseMini').forEach(card=>card.onclick=()=>openCatalog({query:card.textContent.trim().replace(/\s+/g,' ')}))}
function renderCatalog(){const root=$('#catalog');const brands=[...new Set(state.catalog.records.map(r=>r.brand))];const cats=[...new Set(state.catalog.records.map(r=>r.cat))];let rows=state.catalog.records.filter(r=>(!state.query||(r.brand+' '+r.product+' '+r.frameColor+' '+r.lensName+' '+r.frameFamily+' '+r.lensHue).toLowerCase().includes(state.query))&&(!state.brand||r.brand===state.brand)&&(!state.cat||r.cat===state.cat)&&(!state.lensHue||r.lensHue===state.lensHue)&&(!state.frameFamily||r.frameFamily===state.frameFamily)).slice(0,360);const chips=[state.lensHue?'<span class="badge">Lens: '+safe(HUE_LABEL[state.lensHue]||state.lensHue)+'</span>':'',state.frameFamily?'<span class="badge">Frame: '+safe(state.frameFamily)+'</span>':''].filter(Boolean).join(' ');const savedCount=overrideCount();root.innerHTML='<div class="toolbar"><input class="input" id="q" placeholder="Search product, lens, frame" value="'+safe(state.query)+'"><select class="select" id="brand"><option value="">All brands</option>'+brands.map(b=>'<option '+(state.brand===b?'selected':'')+'>'+b+'</option>').join('')+'</select><select class="select" id="cat"><option value="">All categories</option>'+cats.map(c=>'<option value="'+c+'" '+(state.cat===c?'selected':'')+'>'+CAT_LABEL[c]+'</option>').join('')+'</select>'+(chips?'<span class="mut">'+chips+'</span><button class="toolBtn" id="clearExact">Clear heatmap filters</button>':'')+'<button class="toolBtn" id="exportOverrides" type="button">Export overrides</button><span class="mut">'+savedCount+' overrides in current page · '+rows.length+' shown</span></div><div class="panel" style="margin-bottom:12px;padding:10px 14px;font-size:12px"><b>⚠ 关于图片颜色与分类标注不符</b>：产品图片展示的是<b>镜架+镜片整体效果</b>，视觉主色由<b>镜架颜色</b>主导。颜色分类（lensHue）依据的是<b>镜片类型</b>，不是图片的整体观感。例如：Warby Parker Black Walnut 镜架配 Blue 蓝色镜片，图片整体偏深棕，但分类为蓝色。卡片中"<b>镜片</b> / <b>镜架</b>"标签可帮助核对。</div><div class="imageGrid">'+rows.map(productCard).join('')+'</div>';$('#q').oninput=e=>{state.query=e.target.value.toLowerCase();renderCatalog()};$('#brand').onchange=e=>{state.brand=e.target.value;renderCatalog()};$('#cat').onchange=e=>{state.cat=e.target.value;renderCatalog()};$('#exportOverrides').onclick=exportOverrides;const clear=$('#clearExact');if(clear)clear.onclick=()=>{state.lensHue='';state.frameFamily='';renderCatalog()};bindManualSave(root)}
function renderDataAdmin(){const root=$('#data');root.innerHTML='<div class="grid2"><section class="panel"><h2>How to update this site</h2><p class="chartNote">当前版本是静态站：这里先作为维护说明页。新数据上传后，需要由维护者或 AI agent 重新分类、重新 build，再部署到 Railway。</p><table class="table"><tbody><tr><td><b>1</b></td><td><b>准备新数据</b><br>可以是新抓下来的品牌 HTML、CSV/JSON catalog，或后端 scraper 输出。必须保留原始 product / lensName / frameColor。</td></tr><tr><td><b>2</b></td><td><b>AI 辅助分类</b><br>让模型只输出结构化 JSON：lensHue、cat、frameFamily、hueHex、confidence。低置信度和 unknown 需要人工确认。</td></tr><tr><td><b>3</b></td><td><b>重新生成</b><br><span class="code">npm run build:all</span> 用于源 HTML 更新；<span class="code">npm run build:site</span> 用于只改图表或页面。</td></tr><tr><td><b>4</b></td><td><b>检查并发布</b><br>运行 <span class="code">node --check outputs/site/app.js</span>，本地预览后推到 Railway。</td></tr></tbody></table></section><section class="panel"><h2>Upload packet requirements</h2><p class="chartNote">以后做成后端上传时，上传包至少要能产出这些字段。没有 hex 的颜色也可以上传，但分类准确度会下降。</p><table class="table"><tbody><tr><td>Required</td><td><span class="code">brand</span> · <span class="code">product</span> · <span class="code">rank</span> · <span class="code">frameColor</span> · <span class="code">lensName</span> · <span class="code">img</span></td></tr><tr><td>Generated</td><td><span class="code">lensHue</span> · <span class="code">hueHex</span> · <span class="code">hueSource</span> · <span class="code">cat</span> · <span class="code">frameFamily</span></td></tr><tr><td>Do not overwrite</td><td>原始品牌命名要保留。标准化字段只作为分析层，不替代原始商品名。</td></tr></tbody></table><div class="adminDrop" style="margin-top:12px"><b>Future upload API shape</b><p class="mut">POST /api/import-brand · POST /api/reclassify · GET /api/catalog · GET /api/insights</p></div></section></div><div class="grid2" style="margin-top:16px"><section class="panel"><h2>Color classification rules</h2><table class="table"><tbody><tr><td>Lens hue</td><td>优先用 <span class="code">hueHex</span>，再用颜色名兜底。统一到 black / grey / brown / amber / yellow / orange / rose / violet / blue / teal / green / unknown；Olive / Khaki 合并进 Green。</td></tr><tr><td>Category</td><td><span class="code">sun</span> 是常规墨镜；<span class="code">tint</span> 是浅色/时装 tint；<span class="code">gradient</span> 是渐变镜片。Gradient 命名优先。</td></tr><tr><td>Frame family</td><td>把 Black、Tortoise、Brown、Silver、Blue 等归入跨品牌可比较的 frameFamily，同时保留原始 frameColor。</td></tr></tbody></table></section><section class="panel"><h2>Maintenance downloads</h2><p class="chartNote">这些文件会随静态网站一起发布。别人只拿到网站目录，也可以从这里下载维护说明和 Codex Skill。</p><div class="toolbar"><button class="toolBtn primary" id="dataExportOverrides" type="button">Export manual overrides</button><button class="toolBtn" id="dataClearOverrides" type="button">Clear local overrides</button></div><table class="table"><tbody><tr><td>Human guide</td><td><a class="sourcePill" href="./docs/MAINTENANCE.md" download>Download MAINTENANCE.md</a></td></tr><tr><td>Codex skill</td><td><a class="sourcePill" href="./docs/sunglasses-color-maintainer.SKILL.md" download>Download SKILL.md</a></td></tr><tr><td>Skill metadata</td><td><a class="sourcePill" href="./docs/sunglasses-color-maintainer.openai.yaml" download>Download openai.yaml</a></td></tr><tr><td>Ask Codex</td><td>“Use the sunglasses-color-maintainer skill to update the sunglasses color site with the new data.”</td></tr><tr><td>Railway</td><td>Railway runs <span class="code">npm start</span>; <span class="code">server.mjs</span> serves <span class="code">outputs/site</span>.</td></tr></tbody></table></section></div>';const ex=$('#dataExportOverrides');if(ex)ex.onclick=exportOverrides;const cl=$('#dataClearOverrides');if(cl)cl.onclick=clearOverrides}
init().catch(err=>{document.body.innerHTML='<pre>'+err.stack+'</pre>'});